// Input is already one job per item
const jobs = items.map(i => i.json);

const blacklist = [
  'software developer',
  'software engineer',
  'frontend',
  'backend',
  'full stack',
  'trainee',
  'coding',
  'machine learning engineer',
  'ml engineer',
  'data scientist',
  'research scientist',
  'java developer',
  'python developer'
];

const whitelist = [
  'data engineer',
  'data platform',
  'data pipeline',
  'etl',
  'elt',
  'elasticsearch',
  'hadoop',
  'spark',
  'kafka',
  'databricks',
  'airflow',
  'mongodb',
  'big data',
  'data infrastructure',
  'data ops',
  'dataops',
  'data integration',
  'analytics engineer'
];

const filtered = jobs.filter(job => {
  // Support both Adzuna (title/description) and Reed (jobTitle/jobDescription) field names
  const title = (job.title || job.jobTitle || '').toLowerCase();
  const body  = (job.description || job.jobDescription || '').toLowerCase();
  const fullText = `${title} ${body}`;

  const hasDE = whitelist.some(w => fullText.includes(w));

  // Only kill if title CLEARLY indicates excluded role
  const isExcludedTitle = blacklist.some(b => title.includes(b));

  return hasDE && !isExcludedTitle;
});

// Return as n8n items
return filtered.map(job => ({ json: job }));

return items.map(item => {
  const job = item.json;

  // ── Detect source by field presence ──────────────────────────────────────
  const isReed = job.jobId !== undefined;

  // ── Normalise raw fields per source ──────────────────────────────────────
  const rawTitle       = isReed ? (job.jobTitle       || '') : (job.title        || '');
  const rawCompany     = isReed ? (job.employerName   || '') : (job.company?.display_name || '');
  const rawLocation    = isReed ? (job.locationName   || '') : (job.location?.display_name || '');
  const rawDesc        = isReed ? (job.jobDescription || '') : (job.description  || '');
  const rawApplyUrl    = isReed ? (job.jobUrl         || '') : (job.redirect_url || '');
  const rawSalaryMin   = isReed ? (job.minimumSalary  || null) : (job.salary_min || null);
  const rawSalaryMax   = isReed ? (job.maximumSalary  || null) : (job.salary_max || null);
  const rawPostedAt    = isReed ? (job.date           || null) : (job.created    || null);
  const rawContractType = isReed
    ? (job.jobType || null)
    : (job.contract_type || job.contract_time || null);
  const rawCategory    = isReed ? null : (job.category?.tag || null);
  const rawEmploymentType = isReed
    ? (job.fullTime === true ? 'full_time' : job.fullTime === false ? 'part_time' : null)
    : (job.contract_time || null);

  // ── Contract/permanent detection ─────────────────────────────────────────
  const desc = rawDesc.toLowerCase();
  const isDailyRate = /per day|\/day|daily rate|inside ir35|outside ir35/i.test(desc);

  let isContract, isPermanent;
  if (isReed) {
    const isHourly = rawSalaryMax !== null && rawSalaryMax < 1000;
    isContract  = isDailyRate && !isHourly;
    isPermanent = !isHourly && !isContract;
  } else {
    isContract  = job.contract_type === 'contract' || job.contract_time === 'contract' || isDailyRate;
    isPermanent = !isContract && (job.contract_time === 'full_time' || job.contract_type === 'permanent');
  }

  // ── Stable job_id (prefix Reed IDs to avoid collisions) ──────────────────
  const jobId = isReed
    ? `reed_${job.jobId}`
    : (job.id || null);

  return {
    json: {
      job_id: jobId,
      source: isReed ? 'Reed' : 'Adzuna',
      title: rawTitle,
      company: rawCompany,
      location: rawLocation,
      job_description: rawDesc,
      apply_url: rawApplyUrl,
      salary_min: rawSalaryMin,
      salary_max: rawSalaryMax,
      salary_is_estimated: isReed ? false : (job.salary_is_predicted || false),
      contract_type: rawContractType,
      employment_type: rawEmploymentType,
      posted_at: rawPostedAt,
      category: rawCategory,
      is_contract: isContract,
      is_permanent: isPermanent,
      llm_input: `
Job Title:
${rawTitle || 'N/A'}

Company:
${rawCompany || 'N/A'}

Location:
${rawLocation || 'N/A'}

Contract Type:
${rawContractType || 'N/A'}

Salary:
${rawSalaryMin || 'N/A'} – ${rawSalaryMax || 'N/A'}

Job Description:
${rawDesc || 'N/A'}
`.trim()
    }
  };
});

const raw = (item.json.text || '').trim();
const originalJob = $('Wait – Rate Limit').item.json;

let parsed;
try {
  const cleanJson = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  return {
    json: {
      ...originalJob,
      score: 0,
      role_type: 'NOT_DE',
      recommendation: 'SKIP',
      reason: 'LLM Error: Failed to parse response JSON.'
    }
  };
}

const score = parsed.score || 0;

// Enforce recommendation based on score thresholds — overrides LLM decision
let recommendation;
if (score >= 60) {
  recommendation = 'APPLY';
} else if (score >= 40) {
  recommendation = 'MAYBE';
} else {
  recommendation = 'SKIP';
}

return {
  json: {
    ...originalJob,
    score,
    role_type: parsed.role_type || 'NOT_DE',
    recommendation,
    reason: parsed.reason || 'Missing reason in LLM response.'
  }
};

const newJobs = $("Normalize – DE Job for LLM").all();

// Safely load history — empty sheet returns 0 items
let sentHistory = [];
try {
  sentHistory = $("Load Sent Job History").all();
  sentHistory = sentHistory.filter(item => item.json.job_id);
} catch(e) {
  sentHistory = [];
}

// Build sets from history: by job_id AND by normalised company+title
const sentIds = new Set(sentHistory.map(item => String(item.json.job_id).trim()));
const sentTitleKeys = new Set(
  sentHistory.map(item => {
    const title = (item.json.title || '').toLowerCase().trim();
    const company = (item.json.company || '').toLowerCase().trim();
    return `${company}||${title}`;
  })
);

// Deduplicate within this run too
const seen = new Set();
const result = [];
for (const item of newJobs) {
  const id = String(item.json.job_id || '').trim();
  const titleKey = `${(item.json.company || '').toLowerCase().trim()}||${(item.json.title || '').toLowerCase().trim()}`;

  if (!sentIds.has(id) && !sentTitleKeys.has(titleKey) && !seen.has(id)) {
    seen.add(id);
    result.push(item);
  }
}
return result;

// Current job item 
const job = $('Parse LLM Result').item.json;

// Safe helper
const safe = (v) => (v === undefined || v === null || v === '' ? 'N/A' : v);

// Description handling
const desc = job.job_description || '';
const shortDesc =
  desc.length > 2000
    ? desc.slice(0, 2000).replace(/\n/g, '<br>') +
      '<br><br><em>[Description truncated]</em>'
    : desc.replace(/\n/g, '<br>');

// Subject
const subject = `[DE Job Match v1.0 – ${safe(job.score)}] ${safe(job.title)} – ${safe(job.company)}`;

return {
  json: {
    to: 'edwardtong@gmail.com',
    subject,
    html: `
<div style="font-family: Arial, Helvetica, sans-serif; font-size: 14px; color: #222;">

  <h2 style="margin-bottom: 4px;">${safe(job.title)}</h2>

  <p style="margin-top: 0; color: #555;">
    <strong>${safe(job.company)}</strong> · ${safe(job.location)}
  </p>

  <hr>

  <table cellpadding="6" cellspacing="0">
    <tr><td><strong>Score</strong></td><td>${safe(job.score)}</td></tr>
    <tr><td><strong>Recommendation</strong></td><td>${safe(job.recommendation)}</td></tr>
    <tr><td><strong>Role Type</strong></td><td>${safe(job.role_type)}</td></tr>
    <tr><td><strong>Reason</strong></td><td>${safe(job.reason)}</td></tr>
    <tr><td><strong>Salary</strong></td>
        <td>£${safe(job.salary_min)} – £${safe(job.salary_max)}</td></tr>
    <tr><td><strong>Contract</strong></td><td>${safe(job.contract_type)}</td></tr>
  </table>

  <p style="margin:16px 0;">
    <a href="${safe(job.apply_url)}"
       style="background:#0d7c3e;color:#fff;padding:10px 16px;
              text-decoration:none;border-radius:4px;font-weight:bold;">
      Apply for this job →
    </a>
  </p>

  <hr>

  <h3>Job Description</h3>
  <p style="line-height:1.5;">${shortDesc || '<em>No description provided</em>'}</p>

  <hr>

  <p style="font-size:12px;color:#777;">
    Sent automatically by n8n · Source: ${safe(job.source)} · Data Engineer Search
  </p>

</div>
`.trim()
  }
};

const seen = new Set();
const output = [];

for (const item of items) {
  const job = item.json;

  let key = job.id || job.jobId;

  if (!key) {
    key = [
      job.title || job.jobTitle || '',
      job.company?.display_name || job.employerName || '',
      job.location?.display_name || job.locationName || ''
    ].join('|').toLowerCase();
  }

  if (!seen.has(key)) {
    seen.add(key);
    output.push({ json: job });
  }
}

return output;

